console.log(vidas !== 0);
console.log(vidas > 5);
console.log(vidas <= 3);

let nome: string = "Aria";
console.log(nome === "Aria");
console.log(nome === "aria");

let hp: number = 100;
let temEscudo: boolean = true;
let nivel: number = 5;

// E (&&): AMBAS precisam ser true
if (hp > 50 && temEscudo) {
  console.log("Pode atacar com segurança!");
}

// OU (||): BASTA UMA ser true
let temPocao: boolean = false;
if (temEscudo || temPocao) {
  console.log("Tem pelo menos um item de proteção");
}

let temPocao: boolean = false;

// NÃO (!): inverte true/false
if (!temPocao) {
  console.log("Sem poção! Compre uma.");
}

// Combinando tudo:
let nivel: number = 10;
let temChave: boolean = true;

if (nivel >= 10 && temChave && !temPocao) {
  console.log("Nível alto e tem chave, mas vai sem poção... boa sorte!");
}

